async (params, browser) => {
  // Open publication page
  await browser.open(`https://medium.com/${params.publication}`)

  // Wait for publication page to load
  await browser.waitForSelector('h1, h2, [class*=\'publication\'], [class*=\'hero\'], article', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load articles
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract publication details
  const publication_data = await browser.evaluate(`const nameEl = document.querySelector('h1, h2[class*="name"], [class*="publication"] h1, [class*="hero"] h1'); const descEl = document.querySelector('[class*="description"], [class*="about"] p, [class*="hero"] p, [class*="tagline"]'); const followersEl = document.querySelector('[class*="follower"] span, [class*="subscriberCount"], button[class*="follow"] + span'); const imgEl = document.querySelector('[class*="publication"] img[class*="logo"], [class*="hero"] img, header img'); const tagEls = document.querySelectorAll('[class*="tags"] a, a[href*="/tag/"]'); const tags = []; tagEls.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 50 && !tags.includes(t)) tags.push(t); }); const articles = []; const articleEls = document.querySelectorAll('article, [data-testid="postPreview"], div[class*="postArticle"]'); for (let i = 0; i < Math.min(articleEls.length, 10); i++) { const el = articleEls[i]; const titleEl = el.querySelector('h2, h3, [class*="title"]'); const authorEl = el.querySelector('a[data-testid="authorName"], a[rel="author"], [class*="author"] a'); const clapsEl = el.querySelector('[class*="clap"] span, button[data-testid="clap"] span'); const dateEl = el.querySelector('time, span[class*="date"]'); const linkEl = el.querySelector('a[href*="/p/"], h2 a, h3 a'); articles.push({ title: titleEl ? titleEl.textContent.trim() : '', author: authorEl ? authorEl.textContent.trim() : '', claps: clapsEl ? clapsEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', url: linkEl ? linkEl.href : '' }); } const editorEls = document.querySelectorAll('[class*="editor"] a, [class*="writer"] a'); const editors = []; editorEls.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 80 && !editors.includes(t)) editors.push(t); }); return { name: nameEl ? nameEl.textContent.trim() : '' + params.publication + '', description: descEl ? descEl.textContent.trim().substring(0, 500) : '', followers: followersEl ? followersEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', tags: tags.slice(0, 10), editors: editors.slice(0, 10), article_count: articles.length, articles: articles, url: window.location.href }`)

  return publication_data
}
